  ('disabled-10ced7e2-moex-00210', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-112-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '關於對公務員懲戒權之行使期間，下列敘述何者正確？', '["逾10年者，不得予以撤職之懲戒", "逾10年者，不得予以免除職務之懲戒", "逾5年者，不得予以休職之懲戒", "逾5年者，不得予以降級之懲戒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00211', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-112-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '主管機關在核准臨時工廠登記（簡稱臨登處分）中載明：法規禁止事業在 取得土地、建物之合法使用證明文件前變更負責人，且不得增加生產設備耗 用之電能及熱能。關於事業違反該義務時之法律效果，下列敘述何者正確？', '["違反該義務屬於臨登處分之解除條件成就，該處分因而失效", "該義務係由法規所定，主管機關應以書面通知其限期履行，必要時課處 怠金促其履行", "該義務屬臨登處分之負擔，當事人違反時，主管機關得廢止該處分", "違反該義務屬臨登處分依據之事實事後變更，主管機關得撤銷該處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00212', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-112-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '依行政程序法規定，行政機關訂定法規命令前，依職權決定毋庸舉行聽證。 關於該法規命令之效力，下列敘述何者正確？', '["法規命令當然無效", "法規命令違法得撤銷", "應聲請司法院解釋法規命令是否無效", "法規命令之效力不受影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
