  ('disabled-10ced7e2-moex-00216', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-112-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '關於行政罰法之處罰法定原則，下列敘述何者正確？', '["行政罰之構成要件、法律效果，應以法律明定，不得授權以命令定之", "地方自治團體對於違反地方自治事項之行為，得規定罰鍰及剝奪資格之 不利處分", "行為時無裁罰之法律規定，裁處時法律變更應受處罰者，以作成裁罰處 分時之法律為準", "行為時依法應處刑罰，裁處時法律變更為裁處行政罰者，以作成裁罰處 分時之法律為準"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
  ('disabled-10ced7e2-moex-00217', 'disabled-10ced7e2', 'disabled-10ced7e2-moex-112-3082b5f1', 'sub-disabled-10ced7e2-07', NULL, 'single_choice', '公務人員甲因涉及貪污治罪條例遭檢察官提起公訴，其服務機關因而予以 免職，甲於免職後，向該服務機關申請閱覽考績委員會之會議紀錄，遭服 務機關否准，對於此否准決定，甲得如何提起救濟？', '["得直接對否准卷宗閱覽之決定另外提起訴願", "得直接對否准卷宗閱覽之決定另外提起行政訴訟", "得對於免職處分提起之救濟程序中，一併聲明不服", "得直接對否准卷宗閱覽之決定，提起國家賠償訴訟"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:50+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": "6c607bd53138", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "disabled", "civil_category": "人事行政"}'::jsonb, NULL),
